"""
GitLab Duo provider adapter — automates the entire onboarding flow:

  Google OAuth (via sign_up) → Identity verification (Gmail OTP) →
  Welcome form → Free Trial (Singapore, 30 days Ultimate) →
  Toggle Duo experiment/beta features → Generate PAT (api scope)

Output (`fetch_tokens`):
  { "pat": "glpat-…", "gitlab_base_url": "https://gitlab.com",
    "namespace_path": "<auto-generated-group>", "username": "<gitlab-handle>" }

The Bun runner picks the PAT up and calls `createGitlabDuoAccount()` to
validate it, fetch model list, and finalize the DB row.

This adapter mirrors the well-tested manual Playwright flow validated against
real accounts. Key gotchas already handled:

  • **Cloudflare Managed Challenge bypass**: /users/sign_in has interactive
    Turnstile that bots cannot solve. We navigate to /users/sign_up instead —
    same Google OAuth button, no challenge. Works for existing AND new accounts
    because GitLab's OmniAuth flow doesn't care which page you came from.
  • Welcome-form labels intercept input clicks → use `label[for=…]` selector.
  • Duo Chat side panel intercepts Save button on /settings/gitlab_duo →
    close it before toggling the experiment checkbox.
  • Country dropdown options use stable testids `listbox-item-SG` etc.
  • PAT scope checkbox is intercepted → click via JS by id.
  • Gmail OTP fetch reuses the same Google session (logged in via OAuth) —
    open a new tab to mail.google.com, scrape the latest GitLab confirm email.
"""
from __future__ import annotations

import asyncio
import json
import os
import re
import time
from typing import Any
from urllib.parse import urlparse

from app.errors.codes import ErrorCode
from app.errors.exceptions import NonRetryableBatcherError, RetryableBatcherError
from app.providers.base import NormalizedAccount, ProviderAdapter

# ---------------------------------------------------------------------------
# Constants
# ---------------------------------------------------------------------------

DEFAULT_BASE_URL = os.getenv("GITLAB_DUO_BASE_URL", "https://gitlab.com").rstrip("/")
# IMPORTANT: We use /users/sign_up instead of /users/sign_in. The sign_up endpoint
# is whitelisted from Cloudflare's Managed Challenge (GitLab keeps signup low-
# friction for conversion), while /users/sign_in is fronted by an interactive
# Turnstile that no headless tool can reliably solve. The sign_up page exposes
# the same "Sign in with Google" OAuth button — clicking it routes through the
# same OmniAuth flow and works equally well for existing AND new accounts.
SIGN_UP_URL = f"{DEFAULT_BASE_URL}/users/sign_up"
SIGN_IN_URL = f"{DEFAULT_BASE_URL}/users/sign_in"  # kept for reference
GMAIL_INBOX_URL = "https://mail.google.com/mail/u/0/#inbox"
PAT_NAME = os.getenv("GITLAB_DUO_PAT_NAME", "poolprox3-duo")

# Step timeouts (in seconds)
NAV_TIMEOUT_S = 60
CLOUDFLARE_TIMEOUT_S = 30  # sign_up is not under managed challenge; quick guard only
OAUTH_TIMEOUT_S = 90
OTP_TIMEOUT_S = 180  # Gmail can take 30-60s to deliver; GitLab batches emails
TRIAL_TIMEOUT_S = 30
DUO_TOGGLE_TIMEOUT_S = 30
PAT_TIMEOUT_S = 30


def _debug(msg: str) -> None:
    if os.getenv("BATCHER_DEBUG", "").lower() == "true":
        print(f"[gitlab-duo-debug] {msg}", flush=True)


def _emit(payload: dict) -> None:
    """Emit a JSON line to stdout — picked up by Bun runner.ts as a progress
    event and streamed to the dashboard via WebSocket."""
    try:
        print(json.dumps(payload), flush=True)
    except BrokenPipeError:
        pass


def _progress(step: str, message: str, **extra: Any) -> None:
    payload = {"type": "progress", "provider": "gitlab-duo", "step": step, "message": message}
    payload.update(extra)
    _emit(payload)


# ---------------------------------------------------------------------------
# Browser launch
# ---------------------------------------------------------------------------

async def _launch_camoufox() -> tuple[Any, Any, Any]:
    """Launch a fresh Camoufox session with anti-bot fingerprint and (optional)
    proxy. Returns (manager, browser, page).

    Each call returns an isolated browser → no profile/cookie leak between
    accounts when the queue runs them in parallel.
    """
    try:
        from browserforge.fingerprints import Screen
        from camoufox.async_api import AsyncCamoufox
    except Exception as exc:
        raise RetryableBatcherError(
            ErrorCode.browser_start_failed,
            f"camoufox import failed: {exc}",
        ) from exc

    camoufox_kwargs: dict[str, Any] = {
        "headless": os.getenv("BATCHER_CAMOUFOX_HEADLESS", "false").lower() == "true",
        "os": "windows",
        "block_webrtc": True,
        "humanize": False,
        "screen": Screen(max_width=1920, max_height=1080),
    }

    proxy_url = os.getenv("BATCHER_PROXY_URL", "").strip()
    if proxy_url:
        parsed = urlparse(proxy_url)
        proxy_cfg: dict[str, Any] = {
            "server": f"{parsed.scheme}://{parsed.hostname}:{parsed.port}"
        }
        if parsed.username:
            proxy_cfg["username"] = parsed.username
        if parsed.password:
            proxy_cfg["password"] = parsed.password
        camoufox_kwargs["proxy"] = proxy_cfg
        camoufox_kwargs["geoip"] = True

    try:
        manager = AsyncCamoufox(**camoufox_kwargs)
        browser = await manager.__aenter__()
        page = await browser.new_page()
        page.set_default_timeout(NAV_TIMEOUT_S * 1000)
        return manager, browser, page
    except Exception as exc:
        raise RetryableBatcherError(
            ErrorCode.browser_start_failed,
            f"camoufox launch failed: {exc}",
        ) from exc


# ---------------------------------------------------------------------------
# Login: GitLab → Google OAuth
# ---------------------------------------------------------------------------

async def _wait_past_cloudflare(page: Any, timeout_s: int = CLOUDFLARE_TIMEOUT_S) -> None:
    """Page-ready guard on /users/sign_up.

    sign_up is NOT fronted by Cloudflare Managed Challenge (verified manually),
    so this is mostly a quick "is the form ready" check rather than a real CF
    poll loop. Returns when the Google OAuth button is visible.
    """
    deadline = time.monotonic() + timeout_s
    selectors = (
        'button[data-provider="google_oauth2"]',  # sign_up form button
        'form[action*="google_oauth2"] button',   # sign_up form button (fallback)
        'a[href*="/users/auth/google_oauth2"]',   # legacy sign_in anchor
    )
    while time.monotonic() < deadline:
        try:
            for sel in selectors:
                count = await page.locator(sel).count()
                if count > 0:
                    visible = await page.locator(sel).first.is_visible()
                    if visible:
                        return
        except Exception:
            pass
        await asyncio.sleep(1.0)
    raise RetryableBatcherError(
        ErrorCode.browser_challenge_blocked,
        "Sign-up page did not render Google OAuth button within %ds" % timeout_s,
    )


async def _click_google_oauth(page: Any) -> None:
    """Click the 'Sign in with Google' button.

    On /users/sign_up this is a real <button type="submit"> inside a POST form
    that includes the CSRF authenticity_token — clicking submits the form,
    which redirects through GitLab's OmniAuth handler and ends up at
    accounts.google.com. On older /users/sign_in pages it's an <a href> link.

    NOTE on `no_wait_after=True`: Playwright 1.60 + Firefox has a known driver
    bug where querying or auto-waiting after a navigating click can crash the
    driver process with "Cannot read properties of undefined (reading 'url')".
    We bypass the auto-wait and let the caller handle navigation via
    `wait_for_url`.
    """
    selectors = (
        'button[data-provider="google_oauth2"]',
        'form[action*="google_oauth2"] button',
        'a[href*="/users/auth/google_oauth2"]',
    )
    last_exc: Exception | None = None
    for sel in selectors:
        try:
            count = await page.locator(sel).count()
            if count == 0:
                continue
            # no_wait_after=True is critical — see docstring above.
            await page.locator(sel).first.click(timeout=10000, no_wait_after=True)
            return
        except Exception as exc:
            last_exc = exc
            continue
    raise RetryableBatcherError(
        ErrorCode.browser_element_not_found,
        f"Google OAuth button not clickable: {last_exc}",
    )


# --- Google flow primitives (adopted from codebuddy.py state-machine) ---

async def _is_email_step(page: Any) -> bool:
    """True if Google's email input is visible (we're at the identifier step)."""
    try:
        return bool(
            await page.evaluate(
                """() => {
                    for (const el of document.querySelectorAll(
                        '#identifierId, input[name="identifier"], input[type="email"]'
                    )) {
                        if (el.offsetParent !== null) return true;
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _is_password_step(page: Any) -> bool:
    """True if Google's password input is visible (we're at the password step)."""
    try:
        return bool(
            await page.evaluate(
                """() => {
                    for (const el of document.querySelectorAll(
                        'input[type="password"], input[name="Passwd"]'
                    )) {
                        if (el.offsetParent !== null) return true;
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _is_account_picker(page: Any) -> bool:
    """True if Google is showing the 'Choose an account' / 'Continue as X' picker.

    NOTE: Excludes email/password steps to avoid false positives.
    """
    try:
        return bool(
            await page.evaluate(
                """() => {
                    // Exclude email/password steps
                    for (const el of document.querySelectorAll('input[type="password"], input[name="Passwd"]')) {
                        if (el.offsetParent !== null) return false;
                    }
                    for (const el of document.querySelectorAll('#identifierId, input[name="identifier"], input[type="email"]')) {
                        if (el.offsetParent !== null) return false;
                    }
                    // Look for picker entries
                    const sels = [
                        'div[data-identifier]',
                        'div[data-email]',
                        'li[data-identifier]',
                        'div.BHzsHc',
                    ];
                    for (const sel of sels) {
                        for (const el of document.querySelectorAll(sel)) {
                            if (el.offsetParent === null) continue;
                            const text = (el.textContent || '').toLowerCase();
                            if (text.includes('@')) return true;
                        }
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _click_account_in_picker(page: Any, email: str) -> bool:
    """Click the row in the account picker that matches `email`."""
    try:
        clicked = bool(
            await page.evaluate(
                """(email) => {
                    const lower = email.toLowerCase();
                    const sels = [
                        'div[data-identifier]',
                        'div[data-email]',
                        'li[data-identifier]',
                        'div.BHzsHc',
                    ];
                    for (const sel of sels) {
                        for (const el of document.querySelectorAll(sel)) {
                            if (el.offsetParent === null) continue;
                            const ident = (el.getAttribute('data-identifier') || el.getAttribute('data-email') || '').toLowerCase();
                            const txt = (el.textContent || '').toLowerCase();
                            if (ident === lower || txt.includes(lower)) {
                                el.click();
                                return true;
                            }
                            const parent = el.closest('div[role="link"], li, button');
                            if (parent && parent.offsetParent !== null) {
                                if (txt.includes(lower)) {
                                    parent.click();
                                    return true;
                                }
                            }
                        }
                    }
                    return false;
                }""",
                email,
            )
        )
        if clicked:
            await asyncio.sleep(1.0)
        return clicked
    except Exception:
        return False


async def _click_google_next(page: Any) -> bool:
    """JS-click Google's Next button (#identifierNext / #passwordNext).
    Returns True if a button was clicked."""
    try:
        return bool(
            await page.evaluate(
                """() => {
                    const btn = document.querySelector(
                        '#identifierNext button, #passwordNext button, #identifierNext, #passwordNext'
                    );
                    if (btn && btn.offsetParent !== null) {
                        btn.click();
                        return true;
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _click_consent_only(page: Any) -> bool:
    """Klik HANYA tombol consent OAuth: text 'continue' (exact) atau
    contains 'allow' / 'lanjut' / 'lanjutkan' / 'izinkan'.

    Sengaja TIDAK menerima keyword umum seperti 'next', 'masuk', 'sign in',
    'ok', 'got it' — itu sumber misclick di halaman challenge (mis. tombol
    'Try another way' atau secondary button di selection page).

    Mirror codebuddy._handle_google_consent_continue.
    """
    try:
        return bool(
            await page.evaluate(
                """() => {
                    const exact = new Set(['continue', 'lanjut', 'lanjutkan', 'izinkan']);
                    const contains = ['allow'];
                    for (const el of document.querySelectorAll('button, div[role="button"], input[type="submit"]')) {
                        if (el.offsetParent === null) continue;
                        const txt = (el.textContent || el.value || '').trim().toLowerCase();
                        if (!txt || txt.length > 60) continue;
                        if (exact.has(txt) || contains.some(k => txt.includes(k))) {
                            el.click();
                            return true;
                        }
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _click_picker_continue(page: Any) -> bool:
    """Klik tombol 'Continue as <name>' / 'Sign in as <name>' di account
    picker / oauthchooseaccount page. Pisah dari consent supaya tidak
    bocor ke halaman lain."""
    try:
        return bool(
            await page.evaluate(
                """() => {
                    const prefixes = ['continue as', 'sign in as', 'masuk sebagai', 'lanjutkan sebagai'];
                    for (const el of document.querySelectorAll('button, div[role="button"], input[type="submit"]')) {
                        if (el.offsetParent === null) continue;
                        const txt = (el.textContent || el.value || '').trim().toLowerCase();
                        if (!txt || txt.length > 80) continue;
                        if (prefixes.some(p => txt.startsWith(p))) {
                            el.click();
                            return true;
                        }
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _handle_google_interstitial(page: Any) -> bool:
    """Klik tombol konfirmasi di halaman antara Google: speedbump/gaplustos,
    /challenge/dp (device prompt), /challenge/selection ("How do you want to
    verify"), /challenge/ipp ("It's you") yang punya tombol
    Continue/Confirm/Understand.

    Mirror codebuddy._handle_google_gaplustos: keyword multi-bahasa, exact
    atau prefix-match supaya tidak bocor ke tombol generic.
    """
    try:
        return bool(
            await page.evaluate(
                """() => {
                    // Exact-match supaya tidak misclick — tombol challenge Google
                    // selalu pakai label pendek dan bersih ('Continue', 'Confirm',
                    // 'I understand', 'Got it', 'Lanjutkan', 'Mengerti').
                    const exact = new Set([
                        'continue', 'confirm', 'i understand', 'got it', 'ok',
                        'lanjut', 'lanjutkan', 'konfirmasi', 'mengerti', 'oke',
                        'yes', 'ya', "it's me", 'yes, it\\'s me',
                    ]);
                    for (const el of document.querySelectorAll('button, div[role="button"], input[type="submit"]')) {
                        if (el.offsetParent === null) continue;
                        const txt = (el.textContent || el.value || '').trim().toLowerCase();
                        if (!txt || txt.length > 30) continue;
                        if (exact.has(txt)) {
                            el.click();
                            return true;
                        }
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


# Backwards-compat alias agar kode lama yang masih reference `_click_continue_or_allow`
# tidak crash. Akan dihapus setelah semua caller migrasi.
async def _click_continue_or_allow(page: Any) -> bool:
    """DEPRECATED: dipecah jadi _click_consent_only / _click_picker_continue /
    _handle_google_interstitial. Shim ini delegasi ke ketiganya secara berurutan."""
    if await _click_picker_continue(page):
        return True
    if await _handle_google_interstitial(page):
        return True
    return await _click_consent_only(page)


async def _fill_google_email_step(page: Any, email: str) -> bool:
    """Type email, verify length, click Next. Returns True on success.

    Retries on the same page object if Google's loading overlay swallowed our
    keystrokes (typed_len < expected). Pattern matches codebuddy.
    """
    selectors = ('#identifierId', 'input[name="identifier"]', 'input[type="email"]')
    for sel in selectors:
        try:
            try:
                await page.wait_for_selector(sel, state="visible", timeout=3000)
            except Exception:
                continue
            loc = page.locator(sel).first
            if await loc.count() == 0 or not await loc.is_visible():
                continue
            await loc.scroll_into_view_if_needed()
            await loc.click(force=True)
            await asyncio.sleep(0.2)
            try:
                await loc.press("Control+a")
                await loc.press("Backspace")
            except Exception:
                pass
            try:
                await loc.press_sequentially(email, delay=70)
            except Exception as exc:
                _debug(f"email press_sequentially failed sel={sel} err={exc}")
                continue
            await asyncio.sleep(0.4)
            typed_len = 0
            try:
                typed_len = len(str(await loc.input_value()))
            except Exception:
                try:
                    typed_len = int(
                        await page.evaluate(
                            "(s) => { const el = document.querySelector(s); return el ? el.value.length : 0; }",
                            sel,
                        )
                    )
                except Exception:
                    pass
            _debug(f"email typed length={typed_len} expected={len(email)}")
            if typed_len >= len(email):
                if not await _click_google_next(page):
                    try:
                        await loc.press("Enter")
                    except Exception:
                        pass
                return True
        except Exception as exc:
            _debug(f"email fill error sel={sel} err={exc}")
            continue
    return False


