# Google challenge classification.
#
# Sebelumnya semua /challenge/* + speedbump dianggap fatal 2FA. Itu BUG:
# halaman seperti /challenge/dp (device prompt), /challenge/selection
# ("How do you want to verify it's you"), /challenge/ipp, dan /speedbump/
# (gaplustos) sering muncul di first-login dari device/IP baru bahkan ketika
# akun TIDAK punya 2FA aktif — dan punya tombol Continue/Confirm yang valid
# untuk diklik. Codebuddy tidak pernah memperlakukan URL ini sebagai fail.
#
# Aturan baru:
#   • _HARD_FAIL_MARKERS: benar-benar butuh 2FA/captcha → NonRetryable.
#   • _SOFT_INTERSTITIAL_MARKERS: halaman antara — coba klik Continue/Confirm
#     via _handle_google_interstitial; tidak pernah raise di sini.
_HARD_FAIL_MARKERS = (
    "/challenge/totp",       # Authenticator code
    "/challenge/skotp",      # Backup code (variant of totp)
    "/challenge/sk",         # Security key
    "/challenge/recaptcha",  # Captcha — bot tidak bisa solve
    "phoneverify",           # SMS phone verify
    "phoneinfo",             # Phone number challenge
)

_SOFT_INTERSTITIAL_MARKERS = (
    "/challenge/dp",        # Device prompt — punya tombol Confirm
    "/challenge/ipp",       # Identity / "It's you" prompt
    "/challenge/iap",       # Identity-aware proxy interstitial
    "/challenge/selection", # "How do you want to verify" — pilih Continue
    "/speedbump/",          # gaplustos security speedbump
    "gaplustos",
)


def _classify_google_url(url: str) -> str:
    """Return 'hard_fail' / 'soft_interstitial' / 'normal'.

    Path-aware (urlparse) supaya tidak salah-match substring di query string
    (mis. tombol Continue dengan param `continue=https://...&...&challenge=`).
    Marker dengan leading slash di-substring-match terhadap path; marker tanpa
    slash di-substring-match terhadap full host+path (untuk frase seperti
    'phoneverify' / 'gaplustos').
    """
    if not url:
        return "normal"
    try:
        parsed = urlparse(url)
        path = parsed.path or ""
        host = parsed.netloc or ""
    except Exception:
        return "normal"

    full = f"{host}{path}"
    for m in _HARD_FAIL_MARKERS:
        if m.startswith("/"):
            if m in path:
                return "hard_fail"
        elif m in full:
            return "hard_fail"
    for m in _SOFT_INTERSTITIAL_MARKERS:
        if m.startswith("/"):
            if m in path:
                return "soft_interstitial"
        elif m in full:
            return "soft_interstitial"
    return "normal"


# Backwards-compat alias — beberapa caller (lihat _wait_for_gitlab_post_oauth
# dulu) mungkin masih reference nama lama. Marker hard-fail saja.
_TWOFA_MARKERS = _HARD_FAIL_MARKERS


async def _drive_google_to_gitlab(page: Any, email: str, password: str, timeout_s: int = 120) -> str:
    """Drive the Google OAuth flow until the browser lands back on gitlab.com.

    Filosofi (mengikuti codebuddy.py):
      • POSITIVE detection: kenali step yang dikenal (email/password/picker)
        dan handle. Halaman lain di accounts.google.com → coba klik
        Continue/Confirm/Allow secara LAYERED, bukan langsung fail.
      • Hard fail SANGAT TERBATAS: hanya TOTP/SK/captcha/phone (lihat
        _HARD_FAIL_MARKERS). /challenge/dp, /challenge/selection,
        /speedbump — semua punya tombol Continue yang valid → di-handle.
      • INACTIVITY TIMER (35s) — reset setiap URL berubah ATAU aksi sukses.
        Jadi network lambat tidak bikin fail prematur, tapi stuck beneran
        tetap ke-detect cepat.

    Returns the gitlab.com URL we landed on. Raises:
      • NonRetryableBatcherError pada 2FA/captcha/phone (HARD_FAIL)
      • RetryableBatcherError pada timeout / inactivity
    """
    INACTIVITY_TIMEOUT = 35.0
    deadline = time.monotonic() + timeout_s
    last_url = ""
    last_state = ""
    email_typed = False
    password_typed = False
    last_progress_at = time.monotonic()

    def _mark_progress(reason: str = "") -> None:
        nonlocal last_progress_at
        last_progress_at = time.monotonic()
        if reason:
            _debug(f"_drive_google: progress ({reason})")

    while time.monotonic() < deadline:
        # Inactivity guard — kalau tidak ada perubahan URL atau aksi sukses
        # dalam 35s, anggap stuck.
        if time.monotonic() - last_progress_at > INACTIVITY_TIMEOUT:
            try:
                title = await page.title()
            except Exception:
                title = ""
            raise RetryableBatcherError(
                ErrorCode.auth_timeout,
                f"Google OAuth stuck — no progress for {INACTIVITY_TIMEOUT}s "
                f"(last url: {last_url}, title: {title!r})",
            )

        try:
            url = page.url
        except Exception:
            url = ""

        # === Terminal: back on GitLab ===
        if url and "gitlab.com" in url and "accounts.google" not in url:
            _debug(f"_drive_google: returned to GitLab: {url}")
            return url

        if url != last_url:
            _debug(f"_drive_google: url={url}")
            last_url = url
            _mark_progress("url-change")

        # === Tier-based challenge classification ===
        challenge = _classify_google_url(url)

        if challenge == "hard_fail":
            raise NonRetryableBatcherError(
                ErrorCode.auth_2fa_required_but_missing,
                f"Google hard challenge (2FA/captcha/phone): {url}",
            )

        # === Off-Google host: redirecting, just wait briefly ===
        on_google = "accounts.google.com" in url
        if not on_google:
            await asyncio.sleep(0.5)
            continue

        # === Soft interstitial — Continue/Confirm button page ===
        # Handle SEBELUM step detection karena halaman ini biasanya tidak
        # punya input field email/password sehingga akan jatuh ke "other"
        # dan kita ingin pakai handler khusus, bukan generic.
        if challenge == "soft_interstitial":
            if await _handle_google_interstitial(page):
                _debug(f"_drive_google: interstitial handled on {url}")
                _mark_progress("interstitial-clicked")
                await asyncio.sleep(1.2)
                continue
            # Tidak ketemu tombol exact — coba consent-style fallback
            # (kadang challenge selection juga punya tombol 'Try a different
            # way' tapi tidak match exact list di atas; consent-only masih
            # ketat enough).
            if await _click_consent_only(page):
                _debug(f"_drive_google: consent-only fallback on interstitial {url}")
                _mark_progress("consent-fallback")
                await asyncio.sleep(1.2)
                continue
            # Belum ketemu tombol — jangan fail, biarkan loop lanjut & log saja.
            await asyncio.sleep(0.8)
            continue

        # === Step detection (mutually exclusive) ===
        at_password = await _is_password_step(page)
        at_email = False if at_password else await _is_email_step(page)
        at_picker = False
        if not at_password and not at_email:
            at_picker = await _is_account_picker(page)

        state = (
            "password" if at_password
            else "email" if at_email
            else "picker" if at_picker
            else "other"
        )
        if state != last_state:
            _debug(f"_drive_google: state={state}")
            last_state = state
            _mark_progress(f"state→{state}")

        # === Actions ===
        if at_picker:
            clicked = await _click_account_in_picker(page, email)
            if clicked:
                _debug("_drive_google: clicked account in picker")
                _mark_progress("picker-clicked")
                await asyncio.sleep(1.5)
                continue
            # Fallback: tombol "Continue as <name>"
            if await _click_picker_continue(page):
                _debug("_drive_google: clicked Continue-as on picker")
                _mark_progress("picker-continue")
                await asyncio.sleep(1.5)
                continue
            await asyncio.sleep(0.6)
            continue

        if at_password:
            if not password_typed:
                _debug("_drive_google: filling password")
                if await _fill_google_password_step(page, password):
                    password_typed = True
                    _mark_progress("password-filled")
                    await asyncio.sleep(1.5)
                    continue
                # Fill failed — page may have re-rendered, try next iteration
                await asyncio.sleep(0.8)
                continue
            # Password already typed; spam Next in case loading overlay ate the click
            await _click_google_next(page)
            await asyncio.sleep(0.8)
            continue

        if at_email:
            if not email_typed:
                _debug("_drive_google: filling email")
                if await _fill_google_email_step(page, email):
                    email_typed = True
                    _mark_progress("email-filled")
                    await asyncio.sleep(1.5)
                    continue
                await asyncio.sleep(0.8)
                continue
            await _click_google_next(page)
            await asyncio.sleep(0.8)
            continue

        # === Other Google page (consent screen / "Continue as X" / unknown) ===
        # Layered click: picker-continue → consent-only. JANGAN pakai keyword
        # generic 'next/ok/sign in' supaya tidak misclick di edge cases.
        if await _click_picker_continue(page):
            _debug(f"_drive_google: picker-continue on {url}")
            _mark_progress("other-picker-continue")
            await asyncio.sleep(1.2)
            continue
        if await _click_consent_only(page):
            _debug(f"_drive_google: consent-only on {url}")
            _mark_progress("other-consent")
            await asyncio.sleep(1.2)
            continue

        await asyncio.sleep(0.6)

    raise RetryableBatcherError(
        ErrorCode.auth_timeout,
        f"Did not return to GitLab after Google OAuth (last url: {last_url})",
    )


async def _fill_google_login(page: Any, email: str, password: str) -> None:
    """Backwards-compat wrapper. The real work is in _drive_google_to_gitlab,
    which now also subsumes _wait_for_gitlab_post_oauth — but to keep the
    authenticate() flow easy to follow, we expose two phases:
      1) _fill_google_login: ensure email + password are accepted (by driving
         the state machine until we leave both steps),
      2) _wait_for_gitlab_post_oauth: continue driving until we land on
         gitlab.com (handles consent screen, account picker, etc).

    Both phases call into the same state machine; the split is purely
    cosmetic / progress-reporting.
    """
    # Phase 1: drive until we leave password step. We give ourselves up to 60s
    # for the email→password chain because Google can be slow on first login.
    deadline = time.monotonic() + 60
    last_url = ""
    while time.monotonic() < deadline:
        try:
            url = page.url
        except Exception:
            url = ""

        # Hanya hard-fail untuk 2FA betulan — soft interstitial (dp/selection/
        # speedbump) dilewatkan ke _drive_google_to_gitlab / post-oauth wait
        # supaya tombol Continue-nya bisa diklik.
        if _classify_google_url(url) == "hard_fail":
            raise NonRetryableBatcherError(
                ErrorCode.auth_2fa_required_but_missing,
                f"Google hard challenge (2FA/captcha/phone): {url}",
            )

        if url != last_url:
            _debug(f"_fill_google_login: url={url}")
            last_url = url

        if "accounts.google.com" not in url:
            return  # already past Google

        if await _is_email_step(page):
            await _fill_google_email_step(page, email)
            await asyncio.sleep(1.5)
            continue
        if await _is_password_step(page):
            await _fill_google_password_step(page, password)
            await asyncio.sleep(1.5)
            continue
        # Picker / consent / interstitial / other — let _wait_for_gitlab_post_oauth
        # / _drive_google_to_gitlab handle it dengan layered click.
        return

    # If we got here without leaving Google, downstream wait will catch it.
    return


async def _click_consent_continue(page: Any) -> bool:
    """Backwards-compat shim untuk kode lama. Sekarang LAYERED:
    interstitial → picker-continue → consent-only."""
    try:
        if await _handle_google_interstitial(page):
            return True
        if await _click_picker_continue(page):
            return True
        return await _click_consent_only(page)
    except Exception:
        return False


async def _wait_for_gitlab_post_oauth(page: Any, timeout_s: int = 90) -> str:
    """After Google approves, the browser bounces to GitLab. Returns the URL
    we actually landed on (could be identity_verification, welcome, dashboard,
    etc — caller branches on it).

    Sekarang pakai layered handling yang sama dengan _drive_google_to_gitlab:
      • _HARD_FAIL_MARKERS → NonRetryable
      • _SOFT_INTERSTITIAL_MARKERS → klik via _handle_google_interstitial
      • OAuth consent screen → klik via _click_consent_only / _click_picker_continue
      • Inactivity timer (35s) — reset setiap URL berubah
    """
    INACTIVITY_TIMEOUT = 35.0
    deadline = time.monotonic() + timeout_s
    last_url = ""
    last_progress_at = time.monotonic()

    while time.monotonic() < deadline:
        if time.monotonic() - last_progress_at > INACTIVITY_TIMEOUT:
            raise RetryableBatcherError(
                ErrorCode.auth_timeout,
                f"post-oauth wait stuck for {INACTIVITY_TIMEOUT}s (last url: {last_url})",
            )
        try:
            url = page.url
            if url != last_url:
                _debug(f"_wait_for_gitlab_post_oauth: url={url}")
                last_url = url
                last_progress_at = time.monotonic()
            if "gitlab.com" in url and "accounts.google" not in url:
                return url

            if "accounts.google.com" in url:
                challenge = _classify_google_url(url)
                if challenge == "hard_fail":
                    raise NonRetryableBatcherError(
                        ErrorCode.auth_2fa_required_but_missing,
                        f"Google hard challenge (2FA/captcha/phone): {url}",
                    )
                if challenge == "soft_interstitial":
                    if await _handle_google_interstitial(page):
                        _debug("post-oauth: interstitial handled")
                        last_progress_at = time.monotonic()
                        await asyncio.sleep(1.0)
                # OAuth consent screen path ("GitLab wants access to your account")
                elif "signin/oauth/consent" in url or "/oauth/consent" in url or "oauthchooseaccount" in url:
                    if await _click_picker_continue(page) or await _click_consent_only(page):
                        _debug("post-oauth: consent/picker clicked")
                        last_progress_at = time.monotonic()
                        await asyncio.sleep(1.0)
                else:
                    # Edge case: tombol Continue mungkin muncul di halaman lain
                    # tanpa marker URL. Coba consent-only saja (ketat), bukan
                    # generic.
                    if await _click_consent_only(page):
                        last_progress_at = time.monotonic()
                if "/identifier" in url:
                    # Still on the email step — likely "couldn't find account"
                    try:
                        page_text = await page.locator("body").inner_text(timeout=2000)
                        for marker in (
                            "Couldn't find your Google Account",
                            "couldn't find your Google Account",
                            "Wrong password",
                            "Try again",
                        ):
                            if marker.lower() in page_text.lower():
                                raise NonRetryableBatcherError(
                                    ErrorCode.auth_invalid_credentials,
                                    f"Google rejected the account: {marker}",
                                )
                    except NonRetryableBatcherError:
                        raise
                    except Exception:
                        pass
        except NonRetryableBatcherError:
            raise
        except Exception:
            pass
        await asyncio.sleep(1.0)
    raise RetryableBatcherError(
        ErrorCode.auth_timeout,
        f"Did not return to GitLab after Google OAuth (last url: {last_url})",
    )


# ---------------------------------------------------------------------------
# Gmail OTP fetch
# ---------------------------------------------------------------------------

_OTP_RE = re.compile(r"\b(\d{6})\b")


async def _fetch_otp_from_gmail(page: Any, timeout_s: int = OTP_TIMEOUT_S) -> str:
    """Navigate the *same tab* to Gmail, scrape the latest 'GitLab: Confirm
    your email' message, then navigate back to the verification page.

    IMPORTANT: We reuse the existing GitLab tab via `page.goto()` instead of
    `browser.new_page()`. Camoufox/Firefox sometimes does not share the
    Google session (cookies/sessionStorage) with a brand-new tab, which
    would force the user to re-login on Gmail — defeating the whole flow.
    Reusing the same tab preserves the session reliably (same approach
    codebuddy uses).

    Returns the 6-digit OTP. Polls every 5s — Gmail web sometimes needs
    ~30s for the message to land.
    """
    # Save the verification page URL so we can come back after grabbing OTP
    try:
        verify_url = page.url
    except Exception:
        verify_url = ""
    _debug(f"_fetch_otp_from_gmail: saved verify_url={verify_url[:120]}")

    try:
        await page.goto(GMAIL_INBOX_URL, wait_until="domcontentloaded", timeout=30000)
        await asyncio.sleep(3)

        # If Gmail bounced us to a Google sign-in page, the session was lost.
        # Bail out so the caller can retry — re-login is non-trivial here.
        try:
            gurl = page.url
        except Exception:
            gurl = ""
        if "accounts.google.com" in gurl:
            _debug(f"_fetch_otp_from_gmail: Gmail redirected to Google login: {gurl}")
            # Try to navigate back to verification page so retry has a chance
            if verify_url:
                try:
                    await page.goto(verify_url, wait_until="domcontentloaded", timeout=15000)
                except Exception:
                    pass
            raise RetryableBatcherError(
                ErrorCode.auth_temporary_failure,
                "Gmail session not shared with this tab — re-login was requested",
            )
        # Wait for inbox grid
        try:
            await page.locator('div[role="main"]').first.wait_for(state="visible", timeout=20000)
        except Exception:
            pass

        deadline = time.monotonic() + timeout_s
        last_seen_subject = ""
        otp_found: str | None = None
        confirm_link: str | None = None

        while time.monotonic() < deadline and otp_found is None and confirm_link is None:
            try:
                # Refresh inbox via reload (more reliable than clicking the
                # Refresh button which is often hidden behind dynamic UI)
                try:
                    await page.reload(wait_until="domcontentloaded", timeout=15000)
                    await asyncio.sleep(2.5)
                except Exception:
                    pass

                # Wait for inbox grid
                try:
                    await page.locator('div[role="main"]').first.wait_for(state="visible", timeout=10000)
                except Exception:
                    pass

                rows = page.locator('tr.zA')
                row_count = await rows.count()
                _debug(f"Gmail inbox has {row_count} rows visible")

                # Find first row that mentions GitLab anywhere
                target_row_idx = -1
                target_row_text = ""
                for i in range(min(row_count, 30)):
                    row = rows.nth(i)
                    try:
                        text = (await row.inner_text()).strip()
                    except Exception:
                        continue
                    if re.search(r"gitlab", text, re.I):
                        _debug(f"row {i} matches GitLab: {text[:200]!r}")
                        target_row_idx = i
                        target_row_text = text
                        last_seen_subject = text[:200]
                        break

                if target_row_idx < 0:
                    _debug(f"no GitLab row found among {row_count} rows; sleeping 5s")
                    await asyncio.sleep(5.0)
                    continue

                # FAST PATH: Gmail's row preview often already contains the 6-digit
                # OTP ("...enter the following code. 720744"). If we can pull it
                # from the row text, we don't need to open the email at all —
                # which dodges Gmail click flakiness entirely.
                if target_row_text:
                    m = _OTP_RE.search(target_row_text)
                    if m:
                        otp_found = m.group(1)
                        _debug(f"OTP captured from row preview: {otp_found}")
                        break

                # Open it. Click is flaky (Gmail's tr.zA elements have phantom
                # overlays), so we try several strategies.
                opened = False
                for strat in ("click", "dblclick", "js_click"):
                    try:
                        row_loc = rows.nth(target_row_idx)
                        if strat == "click":
                            await row_loc.click(timeout=3000, force=True)
                        elif strat == "dblclick":
                            await row_loc.dblclick(timeout=3000)
                        else:
                            handle = await row_loc.element_handle(timeout=3000)
                            if handle:
                                await page.evaluate("(el) => el.click()", handle)
                        opened = True
                        _debug(f"row opened via {strat}")
                        break
                    except Exception as exc:
                        _debug(f"row open via {strat} failed: {exc}")
                if not opened:
                    # Last-ditch: try clicking the inner span.bog (subject) directly.
                    try:
                        inner = rows.nth(target_row_idx).locator('span.bog, span.y6, .a4W').first
                        await inner.click(timeout=3000, force=True)
                        opened = True
                        _debug("row opened via inner span")
                    except Exception as exc:
                        _debug(f"row open via inner span failed: {exc}")
                if not opened:
                    await asyncio.sleep(2.0)
                    continue
                await asyncio.sleep(3.0)

                # Dump body text (truncated) for debugging
                try:
                    body_text = await page.locator('div[role="main"]').first.inner_text()
                    _debug(f"=== Gmail email body (first 2000 chars) ===\n{body_text[:2000]}\n=== end ===")
                except Exception as exc:
                    _debug(f"body read failed: {exc}")
                    body_text = ""

                # Strategy 1: 6-digit OTP in body
                if body_text:
                    m = _OTP_RE.search(body_text)
                    if m:
                        otp_found = m.group(1)
                        _debug(f"OTP captured from body: {otp_found}")
                        break

                # Strategy 2: extract confirmation link from rendered <a> tags
                # GitLab confirm-email link looks like:
                #   https://gitlab.com/users/confirmation?confirmation_token=<TOKEN>
                # GitLab identity-verification email link looks like:
                #   https://gitlab.com/-/identity_verification?token=<TOKEN>  (variant)
                try:
                    hrefs = await page.evaluate(
                        """() => {
                            const out = [];
                            for (const a of document.querySelectorAll('div[role="main"] a[href]')) {
                                const h = a.href || '';
                                if (h.length > 0 && h.length < 2000) out.push(h);
                            }
                            return out;
                        }"""
                    )
                except Exception as exc:
                    _debug(f"href extract failed: {exc}")
                    hrefs = []

                _debug(f"found {len(hrefs)} hrefs in email body")
                for h in hrefs[:30]:
                    _debug(f"  href: {h[:160]}")

                for h in hrefs:
                    if re.search(r"gitlab\.com.*(confirmation_token|confirmation\?|verify|identity_verification|reset_password_token)", h, re.I):
                        confirm_link = h
                        _debug(f"confirmation link found: {h[:200]}")
                        break

                if otp_found or confirm_link:
                    break

                # No OTP and no link — go back to inbox, refresh next loop
                try:
                    await page.go_back(timeout=5000)
                except Exception:
                    pass
                await asyncio.sleep(2.0)

            except Exception as exc:
                _debug(f"otp poll error: {exc}")

            if otp_found is None and confirm_link is None:
                await asyncio.sleep(5.0)

        # Decide what to do based on what we found
        if otp_found is None and confirm_link is None:
            if verify_url:
                try:
                    await page.goto(verify_url, wait_until="domcontentloaded", timeout=15000)
                except Exception:
                    pass
            raise RetryableBatcherError(
                ErrorCode.auth_timeout,
                f"No OTP nor confirmation link found in Gmail within {timeout_s}s (last subject: {last_seen_subject!r})",
            )

        # Confirmation link path: navigate to it directly. The link will
        # confirm the account and redirect us to whatever page GitLab wants
        # next (welcome / dashboard / identity_verification continuation).
        if confirm_link is not None:
            _debug(f"navigating to confirmation link: {confirm_link[:200]}")
            try:
                await page.goto(confirm_link, wait_until="domcontentloaded", timeout=30000)
                await asyncio.sleep(3.0)
                _debug(f"after confirmation, page url: {page.url}")
            except Exception as exc:
                _debug(f"confirmation goto failed: {exc}")
            # Return a sentinel — the caller distinguishes by length.
            # An empty OTP signals "we used the link instead", so the caller
            # should skip _submit_otp.
            return ""

        # OTP path
        # Got the OTP — navigate back to the verification page so caller can submit
        if verify_url:
            try:
                await page.goto(verify_url, wait_until="domcontentloaded", timeout=20000)
                await asyncio.sleep(2.0)
            except Exception as exc:
                _debug(f"failed to navigate back to verify_url: {exc}")
        return otp_found
    except RetryableBatcherError:
        raise
    except Exception as exc:
        # On any other failure, attempt to navigate back so the tab is in a
        # recoverable state for retry
        if verify_url:
            try:
                await page.goto(verify_url, wait_until="domcontentloaded", timeout=15000)
            except Exception:
                pass
        raise RetryableBatcherError(
            ErrorCode.auth_temporary_failure,
            f"OTP fetch failed: {exc}",
        ) from exc


async def _trigger_send_otp(page: Any) -> bool:
    """On the identity_verification intro page ("Help us protect your
    account"), click the 'Send code' / 'Send verification code' button to
    make GitLab actually email the OTP.

    Returns True if a Send button was clicked. Idempotent — safe to call
    even if the OTP input is already visible (will simply find no match).
    """
    try:
        return bool(
            await page.evaluate(
                """() => {
                    // 1) Stable testid (some GitLab versions)
                    const byTestId = document.querySelector(
                        '[data-testid="send-code-button"], [data-testid="send-verification-code-button"]'
                    );
                    if (byTestId && byTestId.offsetParent !== null) {
                        byTestId.click();
                        return true;
                    }
                    // 2) Generic text match
                    for (const el of document.querySelectorAll('button, a[role="button"], input[type="submit"]')) {
                        if (el.offsetParent === null) continue;
                        const txt = (el.textContent || el.value || '').trim().toLowerCase();
                        if (!txt || txt.length > 60) continue;
                        if (
                            txt === 'send code' ||
                            txt === 'send verification code' ||
                            txt === 'send' ||
                            txt.startsWith('send code') ||
                            txt.startsWith('send verification') ||
                            txt === 'kirim kode' ||
                            txt === 'kirim'
                        ) {
                            el.click();
                            return true;
                        }
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _otp_input_visible(page: Any) -> bool:
    """True if the 6-digit OTP input is already on screen."""
    try:
        return bool(
            await page.evaluate(
                """() => {
                    const sels = [
                        'input[name="verification_code"]',
                        'input[autocomplete="one-time-code"]',
                        'input[inputmode="numeric"]',
                        'input[id*="code" i]',
                    ];
                    for (const sel of sels) {
                        for (const el of document.querySelectorAll(sel)) {
                            if (el.offsetParent !== null) return true;
                        }
                    }
                    return false;
                }"""
            )
        )
    except Exception:
        return False


async def _ensure_otp_sent(page: Any, timeout_s: int = 30) -> None:
    """Make sure we're on the OTP-input variant of identity_verification.

    GitLab shows two screens here:
      1) Intro: "Help us protect your account" with a [Send code] button
      2) OTP entry: input field for the 6-digit code

    If we're on (1), click [Send code] and wait for (2). If we're already on
    (2), no-op.
    """
    if await _otp_input_visible(page):
        _debug("_ensure_otp_sent: OTP input already visible")
        return

    _progress("otp_send", "Clicking 'Send code' button…")
    clicked = await _trigger_send_otp(page)
    if not clicked:
        _debug("_ensure_otp_sent: no Send button found — page may already be in OTP state")

    # Poll for OTP input to appear
    deadline = time.monotonic() + timeout_s
    while time.monotonic() < deadline:
        if await _otp_input_visible(page):
            _debug(f"_ensure_otp_sent: OTP input appeared after click")
            return
        # Re-click in case the first click was eaten by a loading overlay
        await _trigger_send_otp(page)
        await asyncio.sleep(1.5)

    _debug(f"_ensure_otp_sent: OTP input did not appear in {timeout_s}s — proceeding anyway")


async def _submit_otp(page: Any, otp: str) -> None:
    """On gitlab.com/users/identity_verification — fill OTP, submit."""
    try:
        otp_input = page.locator(
            'input[name="verification_code"], input[autocomplete="one-time-code"], '
            'input[inputmode="numeric"], input[id*="code"]'
        ).first
        await otp_input.wait_for(state="visible", timeout=15000)
        await otp_input.fill(otp)
        await asyncio.sleep(0.5)
        # Submit — try button first, then Enter.
        try:
            await page.locator(
                'button[type="submit"], button:has-text("Verify"), '
                'button:has-text("Submit"), button:has-text("Continue")'
            ).first.click(timeout=5000)
        except Exception:
            await otp_input.press("Enter")
        await asyncio.sleep(3.0)
    except Exception as exc:
        raise RetryableBatcherError(
            ErrorCode.browser_unexpected_state,
            f"Failed to submit OTP: {exc}",
        ) from exc


# ---------------------------------------------------------------------------
# Welcome form (only shown on first login of a fresh Google account)
# ---------------------------------------------------------------------------

async def _select_dropdown_option(
    page: Any,
    native_selectors: list[str],
    custom_trigger_selectors: list[str],
    option_label: str,
    field_name: str = "field",
) -> bool:
    """Pick `option_label` in either a native <select> or a GLDropdown.

    GLDropdown is GitLab's custom component: a <button> trigger that opens a
    popover <ul> with <li>/<button> options. Selecting requires:
      1. Click the trigger to open the popover.
      2. Wait for the listbox to render.
      3. Click the option whose visible text matches `option_label`.

    Returns True on success.
    """
    # 1) Try native <select>
    for sel in native_selectors:
        try:
            loc = page.locator(sel).first
            if await loc.count() == 0:
                continue
            await loc.select_option(label=option_label, timeout=4000)
            _debug(f"_select_dropdown_option[{field_name}]: native select succeeded ({sel})")
            return True
        except Exception:
            continue

    # 2) Custom GLDropdown — click trigger, then click option
    trigger = None
    for sel in custom_trigger_selectors:
        try:
            loc = page.locator(sel).first
            if await loc.count() == 0:
                continue
            if not await loc.is_visible():
                continue
            trigger = loc
            _debug(f"_select_dropdown_option[{field_name}]: trigger found ({sel})")
            break
        except Exception:
            continue

    if trigger is None:
        # Last resort: scan all visible buttons for one whose text contains
        # "Select" / role / objective placeholder
        try:
            buttons = await page.evaluate(
                """(fieldName) => {
                    const out = [];
                    const btns = document.querySelectorAll('button, [role="button"]');
                    btns.forEach((b, idx) => {
                        if (b.offsetParent === null) return;
                        const txt = (b.textContent || '').trim();
                        if (!txt || txt.length > 60) return;
                        out.push({ idx, txt });
                    });
                    return out.slice(0, 30);
                }""",
                field_name,
            )
            _debug(f"_select_dropdown_option[{field_name}]: visible buttons = {buttons}")
        except Exception:
            pass
        _debug(f"_select_dropdown_option[{field_name}]: NO trigger found")
        return False

    # Open the dropdown
    try:
        await trigger.scroll_into_view_if_needed()
        await trigger.click(timeout=5000, force=True)
    except Exception as exc:
        _debug(f"_select_dropdown_option[{field_name}]: trigger click failed: {exc}")
        return False

    await asyncio.sleep(0.5)

    # Click the option matching `option_label` from anywhere on the page
    # (popover renders outside the form usually)
    option_selectors = [
        f'[role="option"]:has-text("{option_label}")',
        f'li[role="option"]:has-text("{option_label}")',
        f'[data-testid*="dropdown-item"]:has-text("{option_label}")',
        f'.gl-dropdown-item:has-text("{option_label}")',
        f'button:has-text("{option_label}")',
        f'li:has-text("{option_label}")',
        # Fallback: any element with exact-ish text match
        f'text="{option_label}"',
    ]
    for sel in option_selectors:
        try:
            loc = page.locator(sel).first
            if await loc.count() == 0:
                continue
            if not await loc.is_visible():
                continue
            await loc.click(timeout=3000)
            _debug(f"_select_dropdown_option[{field_name}]: clicked option via {sel}")
            await asyncio.sleep(0.5)
            return True
        except Exception:
            continue

    # Last resort: JS-click anything with that exact text
    try:
        clicked = bool(
            await page.evaluate(
                """(label) => {
                    const target = label.toLowerCase().trim();
                    const candidates = document.querySelectorAll('li, button, [role="option"], a, span, div');
                    for (const el of candidates) {
                        if (el.offsetParent === null) continue;
                        const txt = (el.textContent || '').trim().toLowerCase();
                        if (txt === target) {
                            el.click();
                            return true;
                        }
                    }
                    return false;
                }""",
                option_label,
            )
        )
        if clicked:
            _debug(f"_select_dropdown_option[{field_name}]: JS-clicked exact match")
            return True
    except Exception:
        pass

    _debug(f"_select_dropdown_option[{field_name}]: option {option_label!r} not clickable")
    return False


async def _maybe_fill_welcome_form(page: Any) -> None:
    """If the Welcome page appears, fill the standard fields. If it doesn't,
    silently no-op (some accounts skip it).
    """
    # Detect by URL OR by the role select being present.
    try:
        url = page.url
    except Exception:
        url = ""
    if "users/sign_up/welcome" not in url:
        # Quick poll in case redirect is in flight.
        for _ in range(8):
            await asyncio.sleep(1.0)
            try:
                if "users/sign_up/welcome" in page.url:
                    url = page.url
                    break
            except Exception:
                continue
        if "users/sign_up/welcome" not in url:
            return  # No welcome form — user already onboarded.

    _progress("welcome_form", "Filling welcome form…")

    # Wait for the form to fully render before touching anything
    try:
        await page.wait_for_load_state("domcontentloaded", timeout=10000)
    except Exception:
        pass
    await asyncio.sleep(3.0)

    # Debug: dump form HTML + interactive elements list to /tmp for inspection
    if os.getenv("BATCHER_DEBUG", "").lower() == "true":
        try:
            html = await page.locator('form').first.inner_html()
            from pathlib import Path as _P
            _P("/tmp/duo-debug").mkdir(parents=True, exist_ok=True)
            _P("/tmp/duo-debug/welcome-form.html").write_text(html[:200_000])
            _debug(f"dumped welcome form HTML ({len(html)} chars)")
        except Exception as exc:
            _debug(f"form HTML dump failed: {exc}")
        try:
            elements = await page.evaluate(
                """() => {
                    const out = [];
                    const sels = [
                        'select', 'button', '[role="button"]', '[role="combobox"]',
                        '[role="listbox"]', '[aria-haspopup]', 'div[tabindex]',
                        '.gl-dropdown', '.dropdown-toggle', '.gl-form-select',
                        'input[type="text"]', 'input[type="search"]',
                    ];
                    const seen = new Set();
                    for (const sel of sels) {
                        for (const el of document.querySelectorAll(sel)) {
                            if (seen.has(el)) continue;
                            seen.add(el);
                            if (el.offsetParent === null) continue;
                            const t = el.tagName.toLowerCase();
                            const id = el.id ? `#${el.id}` : '';
                            const dtid = el.getAttribute('data-testid') || '';
                            const role = el.getAttribute('role') || '';
                            const haspopup = el.getAttribute('aria-haspopup') || '';
                            const aria = (el.getAttribute('aria-label') || '').slice(0, 40);
                            const txt = (el.textContent || '').trim().slice(0, 50);
                            out.push(`${t}${id} role=${role} haspopup=${haspopup} testid=${dtid} aria="${aria}" text="${txt}"`);
                        }
                    }
                    return out;
                }"""
            )
            _debug(f"=== welcome interactive elements ({len(elements)}) ===")
            for e in elements:
                _debug(f"  {e}")
        except Exception as exc:
            _debug(f"element dump failed: {exc}")

    # Role + Reason: GitLab uses native <select> elements with stable IDs.
    # Verified by inspecting the live DOM (testid=role-dropdown, native HTML).
    await _select_dropdown_option(
        page,
        native_selectors=[
            'select#user_onboarding_status_role',
            'select[name="user[onboarding_status_role]"]',
            'select[data-testid="role-dropdown"]',
            # Legacy fallbacks
            'select#user_role',
            'select[name="user[role]"]',
        ],
        custom_trigger_selectors=[],
        option_label="Software Developer",
        field_name="role",
    )

    await _select_dropdown_option(
        page,
        native_selectors=[
            'select#user_onboarding_status_registration_objective',
            'select[name="user[onboarding_status_registration_objective]"]',
            # Legacy fallbacks
            'select#user_registration_objective',
            'select[name="user[registration_objective]"]',
        ],
        custom_trigger_selectors=[],
        option_label="I want to store my code",
        field_name="objective",
    )

    # Radios — labels intercept clicks, so click the label[for=…] directly.
    try:
        await page.locator(
            'label[for="user_onboarding_status_joining_project_false"]'
        ).first.click(timeout=8000)
    except Exception:
        pass
    try:
        await page.locator(
            'label[for="user_onboarding_status_setup_for_company_false"]'
        ).first.click(timeout=8000)
    except Exception:
        pass
    # Submit. The button has data-testid="get-started-button" and visible
    # text "Continue" (the page title makes it clear what's being continued).
    try:
        await page.locator('[data-testid="get-started-button"]').first.click(timeout=8000)
    except Exception:
        # Fallbacks
        try:
            await page.locator(
                'button[type="submit"]:has-text("Continue"), '
                'button[type="submit"]:has-text("Get started")'
            ).first.click(timeout=5000)
        except Exception:
            try:
                await page.locator('button[type="submit"]').first.click(timeout=5000)
            except Exception:
                pass
    await asyncio.sleep(3.0)


async def _maybe_fill_groups_form(page: Any, email: str) -> str:
    """Fill /users/sign_up/groups/new — the group creation step that fresh
    accounts MUST complete before reaching the dashboard.

    The form has a single text input for the group name. We derive a name
    from the email local-part (alphanumeric only, max 30 chars).

    Returns the group name actually submitted (caller can correlate dengan
    namespace path nantinya). Raises RetryableBatcherError kalau:
      • Tidak pernah sampai di /users/sign_up/groups/new dalam 15s
      • Submit gagal 3x berturut-turut

    PERUBAHAN: Sebelumnya early-return tanpa poll → race dengan redirect
    lambat. Sekarang poll 15s. Sebelumnya silent give-up after 3 attempts →
    caller tidak tahu fail. Sekarang raise eksplisit.
    """
    try:
        url = page.url
    except Exception:
        url = ""
    # Poll redirect — submit welcome form sometimes takes 5–10s untuk redirect
    # ke /groups/new. Tanpa poll, fungsi ini langsung return → namespace tidak
    # pernah dibuat → trial_claim fail dengan "Could not resolve namespace_id".
    if "/users/sign_up/groups/new" not in url:
        _debug(f"_maybe_fill_groups_form: waiting for redirect (current: {url})")
        for i in range(15):
            await asyncio.sleep(1.0)
            try:
                if "/users/sign_up/groups/new" in page.url:
                    url = page.url
                    _debug(f"_maybe_fill_groups_form: arrived at groups/new after {i+1}s")
                    break
            except Exception:
                continue
        if "/users/sign_up/groups/new" not in url:
            # Caller mungkin sudah lewat group step (akun half-onboarded).
            # Bukan tugas kita untuk raise di sini — biarkan caller verify
            # via _wait_for_dashboard_or_project (yang cek group exists).
            _debug(f"_maybe_fill_groups_form: not on groups/new after 15s poll, skipping (url={url})")
            return ""

    # Wait for the form to render
    try:
        await page.wait_for_load_state("domcontentloaded", timeout=10000)
    except Exception:
        pass
    await asyncio.sleep(2.5)

    # Debug: dump form HTML + interactive elements when BATCHER_DEBUG is on
    if os.getenv("BATCHER_DEBUG", "").lower() == "true":
        try:
            html = await page.locator('form').first.inner_html()
            from pathlib import Path as _P
            _P("/tmp/duo-debug").mkdir(parents=True, exist_ok=True)
            _P("/tmp/duo-debug/groups-form.html").write_text(html[:200_000])
            _debug(f"dumped groups form HTML ({len(html)} chars)")
        except Exception as exc:
            _debug(f"groups form HTML dump failed: {exc}")
        try:
            elements = await page.evaluate(
                """() => {
                    const out = [];
                    const sels = ['input', 'select', 'button', '[role="button"]', '[role="combobox"]'];
                    const seen = new Set();
                    for (const sel of sels) {
                        for (const el of document.querySelectorAll(sel)) {
                            if (seen.has(el)) continue; seen.add(el);
                            if (el.offsetParent === null) continue;
                            const t = el.tagName.toLowerCase();
                            const id = el.id ? `#${el.id}` : '';
                            const name = el.getAttribute('name') ? `[name="${el.getAttribute('name')}"]` : '';
                            const dtid = el.getAttribute('data-testid') || '';
                            const type = el.getAttribute('type') || '';
                            const ph = el.getAttribute('placeholder') || '';
                            const txt = (el.textContent || '').trim().slice(0, 50);
                            out.push(`${t}${id}${name} type=${type} testid=${dtid} placeholder="${ph}" text="${txt}"`);
                        }
                    }
                    return out;
                }"""
            )
            _debug(f"=== groups-form interactive elements ({len(elements)}) ===")
            for e in elements:
                _debug(f"  {e}")
        except Exception as exc:
            _debug(f"groups-form element dump failed: {exc}")

    # Compose a group name. GitLab requires alphanumerics and dashes; min 2 chars.
    # GitLab namespaces are GLOBAL — any collision with an existing path causes
    # silent re-render of the form. We add a short random suffix to avoid that.
    import secrets
    local = email.split("@")[0]
    base = re.sub(r"[^A-Za-z0-9]", "", local)[:18].lower() or "duouser"
    if len(base) < 2:
        base = base + "x"
    suffix = secrets.token_hex(3)  # 6 hex chars
    name = f"{base}{suffix}"
    project_name = f"{name}-proj"

    # Try filling + submitting up to 3 times — on validation failure (taken path,
    # too short, etc.) we regenerate the suffix and retry.
    last_errs: list[str] = []
    for attempt in range(3):
        # Group name
        group_name_selectors = (
            'input#group_name',
            'input[name="group[name]"]',
            'input[data-testid="group-name"]',
            'input[data-testid="group-name-field"]',
        )
        group_filled = False
        for sel in group_name_selectors:
            try:
                loc = page.locator(sel).first
                if await loc.count() == 0 or not await loc.is_visible():
                    continue
                await loc.fill("", timeout=3000)
                await loc.fill(name, timeout=5000)
                _debug(f"_maybe_fill_groups_form[a{attempt}]: filled group name via {sel} = {name!r}")
                group_filled = True
                break
            except Exception:
                continue

        if not group_filled:
            _debug("_maybe_fill_groups_form: could NOT fill group name")
            raise RetryableBatcherError(
                ErrorCode.browser_unexpected_state,
                f"Group name input not found on /users/sign_up/groups/new (url={page.url})",
            )

        # Project name (also required — the submit button is "Create project")
        project_name_selectors = (
            'input#blank_project_name',
            'input[name="project[name]"]',
            'input[data-testid="project-name"]',
        )
        for sel in project_name_selectors:
            try:
                loc = page.locator(sel).first
                if await loc.count() == 0 or not await loc.is_visible():
                    continue
                await loc.fill("", timeout=3000)
                await loc.fill(project_name, timeout=5000)
                _debug(f"_maybe_fill_groups_form[a{attempt}]: filled project name via {sel} = {project_name!r}")
                break
            except Exception:
                continue

        await asyncio.sleep(0.5)

        # Submit. The submit button has data-testid="submit-button" with text "Create project".
        submit_selectors = (
            'button[data-testid="submit-button"][type="submit"]',
            '[data-testid="submit-button"]',
            'button[type="submit"]:has-text("Create project")',
            'button[type="submit"]',
        )
        submitted = False
        for sel in submit_selectors:
            try:
                loc = page.locator(sel).first
                if await loc.count() == 0 or not await loc.is_visible():
                    continue
                await loc.click(timeout=5000)
                _debug(f"_maybe_fill_groups_form[a{attempt}]: submitted via {sel}")
                submitted = True
                break
            except Exception:
                continue

        if not submitted:
            _debug("_maybe_fill_groups_form: could NOT click submit")
            raise RetryableBatcherError(
                ErrorCode.browser_unexpected_state,
                f"Submit button not found on /users/sign_up/groups/new (url={page.url})",
            )

        # Wait for navigation away from /groups/new — up to 25s.
        success = False
        for _ in range(25):
            await asyncio.sleep(1.0)
            try:
                cur = page.url
            except Exception:
                cur = ""
            if "/users/sign_up/groups/new" not in cur and "/users/sign_up/groups" != cur.rstrip("/").split("?")[0].split("gitlab.com")[-1]:
                # Navigated somewhere else — consider it a success.
                _debug(f"_maybe_fill_groups_form[a{attempt}]: navigated to {cur}")
                success = True
                break

        if success:
            return name

        # Validation likely failed. Capture error text + dump HTML.
        err_list: list[str] = []
        try:
            err_list = await page.evaluate(
                """() => {
                    const errs = [];
                    for (const el of document.querySelectorAll('.gl-alert, .gl-alert-danger, [role="alert"], .invalid-feedback, .form-text.gl-text-red-500, .gl-field-error-message')) {
                        const t = (el.textContent || '').trim();
                        if (t) errs.push(t.slice(0, 200));
                    }
                    return errs;
                }"""
            ) or []
            _debug(f"_maybe_fill_groups_form[a{attempt}]: errors after submit = {err_list!r}")
        except Exception:
            pass
        last_errs = err_list

        # Regenerate suffix and retry.
        suffix = secrets.token_hex(4)
        name = f"{base}{suffix}"
        project_name = f"{name}-proj"
        await asyncio.sleep(1.0)

    # All 3 attempts failed — raise so caller doesn't proceed dengan namespace
    # yang belum tercipta. Sebelumnya silent return → trial_claim fail dengan
    # "Could not resolve namespace_id" yang misleading.
    raise RetryableBatcherError(
        ErrorCode.browser_unexpected_state,
        f"Group creation failed after 3 attempts (last errors: {last_errs or 'none'}, url={page.url})",
    )


async def _wait_for_dashboard_or_project(page: Any, timeout_s: int = 45) -> None:
    """After welcome+groups, GitLab routes to dashboard / project / group page.
    Kita perlu memastikan minimal SATU group namespace milik user sudah ada
    (trial endpoint REJECT user namespace — harus group).

    PERUBAHAN: Sebelumnya cuma cek "URL bukan /users/sign_*" → bisa lewat
    groups step (akun half-onboarded yang URL sudah di /-/profile dll).
    Sekarang: tunggu URL non-signup DAN verify via API ada `kind=group`.

    Raises RetryableBatcherError kalau timeout tanpa group terdeteksi.
    """
    deadline = time.monotonic() + timeout_s
    last_url = ""
    last_check_at = 0.0
    has_group_cached = False
    while time.monotonic() < deadline:
        try:
            url = page.url
        except Exception:
            url = ""
        if url != last_url:
            _debug(f"_wait_for_dashboard_or_project: url={url}")
            last_url = url

        on_logged_in = (
            "gitlab.com" in url
            and "/users/sign_" not in url
            and "identity_verification" not in url
            and "/users/confirmation" not in url
        )
        if on_logged_in:
            # Verify group namespace exists. Cache positive result — kalau sudah
            # punya group, tidak perlu cek ulang. Cek max tiap 3s untuk hemat.
            now = time.monotonic()
            if has_group_cached:
                return
            if now - last_check_at >= 3.0:
                last_check_at = now
                try:
                    has_group = await page.evaluate(
                        """async () => {
                            try {
                                const r = await fetch('/api/v4/namespaces?owned=true&per_page=50',
                                    {credentials: 'include'});
                                if (!r.ok) return false;
                                const arr = await r.json();
                                return Array.isArray(arr) && arr.some(n => n.kind === 'group');
                            } catch (e) { return false; }
                        }"""
                    )
                    if has_group:
                        has_group_cached = True
                        _debug("_wait_for_dashboard_or_project: group namespace verified")
                        return
                    else:
                        _debug("_wait_for_dashboard_or_project: no group namespace yet, polling…")
                except Exception as exc:
                    _debug(f"_wait_for_dashboard_or_project: namespace API check failed: {exc}")
        await asyncio.sleep(1.0)

    raise RetryableBatcherError(
        ErrorCode.browser_unexpected_state,
        f"No group namespace exists after onboarding (timeout {timeout_s}s, last url: {last_url})",
    )


# ---------------------------------------------------------------------------
# Free Trial activation
# ---------------------------------------------------------------------------

async def _resolve_namespace_id(page: Any, fallback_path: str | None = None) -> int:
    """Find the user's primary GROUP namespace_id by either:
      (a) Reading the 'Start a Free Trial' link query param (banner only —
          appears on dashboard/billing pages), or
      (b) Hitting /api/v4/namespaces?owned=true via session cookie.

    PERUBAHAN dari sebelumnya:
    • STRICT — hanya return namespace `kind=group`. Sebelumnya ada fallback
      ke `arr[0]?.id` yang bisa balikin user namespace → trial endpoint
      reject (user namespace tidak eligible untuk trial Ultimate).
    • RETRY — sampai 3x dengan delay 2s. Kadang setelah groups submit ada
      eventual-consistency lag sebelum API return group baru.
    • Filter `owned=true` supaya tidak ke-bias dengan group yang user cuma
      member (bukan owner — trial perlu owner role).
    """
    last_err = "no attempt yet"
    for attempt in range(3):
        # (a) Look for trial CTA link (banner di dashboard/billing).
        try:
            href = await page.locator(
                'a[href*="/-/trials/new"][href*="namespace_id="]'
            ).first.get_attribute("href", timeout=2000)
            if href:
                m = re.search(r"namespace_id=(\d+)", href)
                if m:
                    nsid = int(m.group(1))
                    _debug(f"_resolve_namespace_id: from CTA link = {nsid}")
                    return nsid
        except Exception as exc:
            last_err = f"CTA link miss: {exc}"

        # (b) API fetch — STRICT group-only.
        try:
            result = await page.evaluate(
                """async () => {
                    try {
                        const r = await fetch('/api/v4/namespaces?owned=true&per_page=50',
                            {credentials: 'include'});
                        if (!r.ok) return {error: `status ${r.status}`};
                        const arr = await r.json();
                        if (!Array.isArray(arr)) return {error: 'non-array'};
                        const group = arr.find(n => n.kind === 'group');
                        if (group) return {id: group.id, path: group.full_path};
                        // No group namespace yet. Return diagnostics for debug.
                        return {error: 'no-group', kinds: arr.map(n => n.kind)};
                    } catch (e) { return {error: String(e)}; }
                }"""
            )
            if isinstance(result, dict) and isinstance(result.get("id"), (int, float)):
                nsid = int(result["id"])
                _debug(f"_resolve_namespace_id: from API = {nsid} (path={result.get('path')})")
                return nsid
            last_err = f"API returned: {result!r}"
            _debug(f"_resolve_namespace_id[a{attempt}]: {last_err}")
        except Exception as exc:
            last_err = f"API call failed: {exc}"
            _debug(f"_resolve_namespace_id[a{attempt}]: {last_err}")

        # Wait before retry — eventual consistency setelah group creation
        if attempt < 2:
            await asyncio.sleep(2.0)

    raise RetryableBatcherError(
        ErrorCode.browser_unexpected_state,
        f"Could not resolve namespace_id for trial activation (last: {last_err})",
    )


async def _claim_free_trial(page: Any, email: str) -> None:
    """Navigate to /-/trials/new?namespace_id=… and submit the form."""
    namespace_id = await _resolve_namespace_id(page)
    trial_url = (
        f"{DEFAULT_BASE_URL}/-/trials/new?glm_content=chat+panel"
        f"&glm_source=gitlab.com&namespace_id={namespace_id}"
    )
    await page.goto(trial_url, wait_until="domcontentloaded", timeout=30000)
    await asyncio.sleep(2.0)

    # Company name = first 5 chars of the local-part of email (lowercased), padded if shorter.
    local = email.split("@")[0]
    company = re.sub(r"[^A-Za-z0-9]", "", local)[:5].lower()
    if len(company) < 2:
        company = "duouser"

    try:
        await page.get_by_test_id("company-name-field").fill(company, timeout=10000)
    except Exception:
        # Fallback selector
        await page.locator('input[name*="company"], input[id*="company"]').first.fill(company)

    try:
        await page.get_by_test_id("country-dropdown").get_by_test_id(
            "base-dropdown-toggle"
        ).click(timeout=8000)
        await asyncio.sleep(0.5)
        await page.get_by_test_id("listbox-item-SG").click(timeout=8000)
    except Exception as exc:
        raise RetryableBatcherError(
            ErrorCode.browser_element_not_found,
            f"Country (Singapore) selection failed: {exc}",
        ) from exc

    try:
        await page.get_by_test_id("submit-button").click(timeout=8000)
    except Exception:
        # Fallback: any "Activate my trial" button.
        await page.locator('button:has-text("Activate my trial")').first.click(timeout=8000)

    # Wait for redirect away from trial form.
    deadline = time.monotonic() + TRIAL_TIMEOUT_S
    while time.monotonic() < deadline:
        try:
            if "/-/trials/new" not in page.url:
                return
        except Exception:
            pass
        await asyncio.sleep(1.0)


# ---------------------------------------------------------------------------
# Toggle Duo experiment + beta features
# ---------------------------------------------------------------------------

async def _resolve_group_path(page: Any) -> str:
    """Read the user's primary group path from the GitLab sidebar or via API."""
    # Try the sidebar — the current group is named in the breadcrumb.
    try:
        href = await page.locator(
            'a[href^="/groups/"][href*="/-/"]'
        ).first.get_attribute("href", timeout=2000)
        if href:
            m = re.match(r"/groups/([^/]+)/-/", href)
            if m:
                return m.group(1)
    except Exception:
        pass
    # Fallback: API.
    try:
        result = await page.evaluate(
            """async () => {
                const r = await fetch('/api/v4/groups?owned=true&per_page=1', {credentials:'include'});
                if (!r.ok) return null;
                const arr = await r.json();
                return arr[0]?.full_path ?? null;
            }"""
        )
        if isinstance(result, str) and result:
            return result
    except Exception:
        pass
    raise RetryableBatcherError(
        ErrorCode.browser_unexpected_state,
        "Could not resolve group path for Duo configuration",
    )


async def _enable_duo_experiment(page: Any) -> str:
    """Navigate to /groups/<group>/-/settings/gitlab_duo/configuration and
    tick the experimental features checkbox + Save. Returns the group_path
    used (caller may want to persist it)."""
    group_path = await _resolve_group_path(page)
    cfg_url = f"{DEFAULT_BASE_URL}/groups/{group_path}/-/settings/gitlab_duo/configuration"
    await page.goto(cfg_url, wait_until="domcontentloaded", timeout=30000)
    await asyncio.sleep(2.0)

    # The Duo Chat side panel intercepts pointer events on the Save button.
    # Close it first if present.
    try:
        await page.get_by_test_id("content-container-close-button").click(timeout=2500)
        await asyncio.sleep(0.3)
    except Exception:
        pass

    # Tick the "Turn on experiment and beta GitLab Duo features" checkbox.
    try:
        await page.evaluate(
            """() => {
                const cb = document.querySelector('[data-testid="use-experimental-features-checkbox"]');
                if (!cb) return false;
                if (!cb.checked) {
                    const lbl = document.querySelector(`label[for="${cb.id}"]`);
                    if (lbl) lbl.click(); else cb.click();
                }
                return cb.checked === true;
            }"""
        )
    except Exception as exc:
        raise RetryableBatcherError(
            ErrorCode.browser_element_not_found,
            f"Could not toggle experimental-features checkbox: {exc}",
        ) from exc

    # Click Save changes — bypass any pointer interception via direct JS click.
    try:
        clicked = await page.evaluate(
            """() => {
                const btn = [...document.querySelectorAll('button')]
                    .find(b => b.textContent && b.textContent.trim() === 'Save changes');
                if (!btn) return false;
                btn.scrollIntoView({block: 'center'});
                btn.click();
                return true;
            }"""
        )
        if not clicked:
            raise RuntimeError("Save changes button not found")
    except Exception as exc:
        raise RetryableBatcherError(
            ErrorCode.browser_element_not_found,
            f"Could not click Save changes: {exc}",
        ) from exc

    # Wait for the page to navigate or show success indicator.
    deadline = time.monotonic() + DUO_TOGGLE_TIMEOUT_S
    while time.monotonic() < deadline:
        await asyncio.sleep(1.0)
        try:
            url = page.url
            # Save typically redirects to /settings/gitlab_duo (parent).
            if "configuration" not in url or "saved" in url.lower():
                break
        except Exception:
            break

    return group_path


# ---------------------------------------------------------------------------
# Generate PAT
# ---------------------------------------------------------------------------

async def _generate_pat(page: Any, name: str = PAT_NAME) -> str:
    """Navigate to legacy/new, fill name + tick api scope, click generate, scrape token."""
    pat_url = f"{DEFAULT_BASE_URL}/-/user_settings/personal_access_tokens/legacy/new"
    await page.goto(pat_url, wait_until="domcontentloaded", timeout=30000)
    await asyncio.sleep(2.0)

    # Token name
    try:
        await page.get_by_test_id("access-token-name-field").fill(name, timeout=8000)
    except Exception:
        await page.locator('input[id="personal_access_token_name"]').first.fill(name)

    # Tick api scope via JS — the input is intercepted by its label container.
    try:
        ticked = await page.evaluate(
            """() => {
                const cb = document.querySelector('input[type="checkbox"][value="api"]');
                if (!cb) return false;
                if (!cb.checked) {
                    const lbl = document.querySelector(`label[for="${cb.id}"]`);
                    if (lbl) lbl.click(); else cb.click();
                }
                return cb.checked === true;
            }"""
        )
        if not ticked:
            raise RuntimeError("api scope checkbox not found")
    except Exception as exc:
        raise RetryableBatcherError(
            ErrorCode.browser_element_not_found,
            f"Could not tick `api` scope: {exc}",
        ) from exc

    # Click Generate token
    try:
        await page.get_by_test_id("create-token-button").click(timeout=8000)
    except Exception:
        await page.locator('button:has-text("Generate token")').first.click(timeout=8000)

    # Read the displayed token.
    deadline = time.monotonic() + PAT_TIMEOUT_S
    while time.monotonic() < deadline:
        try:
            value = await page.evaluate(
                """() => {
                    const el = document.querySelector('[data-testid="created-access-token-field"]')
                        || document.querySelector('input[readonly][value^="glpat-"]');
                    return el ? (el.value || el.textContent || '').trim() : '';
                }"""
            )
            if value and value.startswith("glpat-"):
                return value
        except Exception:
            pass
        await asyncio.sleep(1.0)

    raise RetryableBatcherError(
        ErrorCode.auth_token_extraction_failed,
        "Generated PAT was not displayed within timeout",
    )


# ---------------------------------------------------------------------------
# Adapter
# ---------------------------------------------------------------------------

class GitLabDuoProviderAdapter(ProviderAdapter):
    name = "gitlab-duo"

    async def parse_account(self, raw_line: str) -> NormalizedAccount:
        parts = [p.strip() for p in raw_line.split("|")]
        if len(parts) < 2 or not parts[0] or not parts[1]:
            raise NonRetryableBatcherError(
                ErrorCode.input_invalid_format,
                f"Expected `email|password` (got {len(parts)} parts)",
            )
        email, password = parts[0], parts[1]
        if "@" not in email:
            raise NonRetryableBatcherError(
                ErrorCode.input_invalid_format,
                f"Invalid email: {email!r}",
            )
        return NormalizedAccount(
            provider=self.name,
            identifier=email,
            secret=password,
            metadata={"raw_email": email},
            raw=raw_line.strip(),
        )

    async def bootstrap_session(self, account: NormalizedAccount) -> Any:
        if os.getenv("BATCHER_ENABLE_CAMOUFOX", "false").lower() != "true":
            raise NonRetryableBatcherError(
                ErrorCode.browser_start_failed,
                "GitLab Duo provider requires BATCHER_ENABLE_CAMOUFOX=true",
            )

        manager, browser, page = await _launch_camoufox()
        try:
            # IMPORTANT: navigate to /users/sign_up (NOT /users/sign_in).
            # sign_in is fronted by Cloudflare Managed Challenge with
            # interactive Turnstile that bots cannot reliably auto-solve.
            # sign_up is whitelisted and exposes the same Google OAuth button.
            await page.goto(SIGN_UP_URL, wait_until="domcontentloaded", timeout=30000)
            _progress("cf_check", "Waiting for sign-up form to render…")
            await _wait_past_cloudflare(page)
        except Exception:
            try:
                await browser.close()
            except Exception:
                pass
            try:
                await manager.__aexit__(None, None, None)
            except Exception:
                pass
            raise

        return {
            "manager": manager,
            "browser": browser,
            "page": page,
        }

    async def authenticate(
        self, account: NormalizedAccount, session: Any
    ) -> dict[str, Any]:
        page = session["page"]
        browser = session["browser"]

        _progress("oauth_click", "Clicking Sign in with Google…")
        await _click_google_oauth(page)

        # Wait for Google OAuth page to load. This avoids a known Playwright
        # 1.60 + Firefox driver crash when locator is queried mid-redirect.
        # The expected redirect chain is: gitlab.com → accounts.google.com.
        try:
            await page.wait_for_url("**accounts.google.com/**", timeout=20_000)
        except Exception:
            # Some accounts skip straight to consent/identity_verification on
            # GitLab if the Google session is already active in this browser
            # context. We only treat this as fatal if neither URL is reached.
            pass
        # Small settle delay for the email input to render
        await asyncio.sleep(2.0)

        _progress("oauth_fill", "Filling Google credentials…")
        # Single state-machine call drives the full Google flow: email step,
        # password step, account picker, "Continue as <name>", OAuth consent.
        # Returns when the browser is back on gitlab.com (or raises on 2FA).
        landed = await _drive_google_to_gitlab(
            page, account.identifier, account.secret, timeout_s=120,
        )
        _progress("oauth_return", f"Returned to GitLab: {landed[:60]}")
        _debug(f"Landed on: {landed}")

        # Identity verification / email confirmation?
        # GitLab uses two distinct flows depending on the account state:
        #  (a) Brand-new signup: email "Confirm your email address" with a
        #      clickable link → we just navigate to the link, no OTP needed.
        #  (b) Existing-account login from new IP: identity_verification
        #      page with "Send code" button → 6-digit OTP via email.
        # The Gmail scraper handles both — it returns "" if it followed a
        # confirmation link (so we skip _submit_otp), or the OTP digits.
        needs_email_action = (
            "identity_verification" in landed
            or "/users/identity_verification" in page.url
            or "/users/confirmation" in page.url
        )
        if needs_email_action:
            # If we're on the identity_verification intro page, click "Send code"
            # to make GitLab actually send the OTP email. (No-op for confirmation flow.)
            if "identity_verification" in page.url:
                await _ensure_otp_sent(page, timeout_s=30)
            _progress("otp_wait", "Fetching OTP / confirmation email…")
            # Reuse the same tab — Camoufox/Firefox sometimes won't share the
            # Google session with a brand-new tab.
            otp = await _fetch_otp_from_gmail(page)
            if otp:
                _progress("otp_found", f"OTP captured: {otp[:2]}••••")
                await _submit_otp(page, otp)
            else:
                _progress("otp_found", "Used confirmation link (no OTP)")

        return {"stage": "authenticated"}

    async def fetch_tokens(
        self,
        account: NormalizedAccount,
        auth_state: dict[str, Any],
        session: Any,
    ) -> dict[str, str]:
        page = session["page"]

        # Welcome form WAJIB diisi untuk akun fresh — jangan coba skip.
        # Sebelumnya kode probe `goto(/)` dulu lalu cek redirect, tapi ada race
        # condition di mana page.url sempat resolve ke "/" sebentar sebelum
        # server bounce balik ke /users/sign_up/welcome — akibatnya cek
        # `if "/users/sign_up/welcome" in page.url` miss dan flow lompat ke
        # trial_claim → gagal dengan "Could not resolve namespace_id".
        #
        # Solusi: navigate EKSPLISIT ke /users/sign_up/welcome dan biarkan
        # _maybe_fill_welcome_form yang menentukan apakah ada form atau tidak
        # (untuk akun yang sudah onboarded, GitLab akan redirect dari
        # /welcome ke dashboard otomatis — fungsi tersebut detect lalu no-op).
        _progress("welcome_goto", "Navigating to welcome form…")
        try:
            await page.goto(
                f"{DEFAULT_BASE_URL}/users/sign_up/welcome",
                wait_until="domcontentloaded",
                timeout=30000,
            )
            await asyncio.sleep(2.5)
            _debug(f"after welcome goto: {page.url}")
        except Exception as exc:
            _debug(f"welcome goto failed: {exc}")

        # Always run the fill helper. It detects the welcome URL itself and
        # silently no-ops if the user is already onboarded (server redirected
        # us to dashboard / projects). For fresh accounts it fills + submits.
        _progress("welcome_form", "Filling welcome form…")
        await _maybe_fill_welcome_form(page)

        # Wait for post-welcome redirect to settle. Setelah submit welcome,
        # server redirect bisa makan 5–10s — TANPA poll, cek `if /groups/new
        # in page.url` di bawah akan MISS dan groups step ke-skip → namespace
        # tidak terbentuk → trial_claim fail dengan "Could not resolve
        # namespace_id". Poll 20s sampai URL stabil.
        _progress("post_welcome_wait", "Waiting for post-welcome redirect…")
        for i in range(20):
            await asyncio.sleep(1.0)
            try:
                cur = page.url
            except Exception:
                continue
            if "/users/sign_up/groups/new" in cur:
                _debug(f"post-welcome: arrived at groups/new after {i+1}s")
                break
            if "/users/sign_up/welcome" not in cur and "/users/sign_up/" not in cur:
                # Sudah lewat sign_up flow (redirect ke dashboard/project).
                # Mungkin akun sudah punya namespace existing.
                _debug(f"post-welcome: redirected past sign_up to {cur}")
                break

        # Defensive force-navigate: kalau masih nyangkut di sign_up tapi BUKAN
        # di groups/new (mis. /users/sign_up/welcome karena submit kena rate
        # limit), force ke /users/sign_up/groups/new. Server akan redirect ke
        # dashboard kalau memang tidak butuh group form (akun lama).
        if "/users/sign_up/" in page.url and "/users/sign_up/groups/new" not in page.url:
            _debug(f"post-welcome: stuck on {page.url}, force-nav to groups/new")
            try:
                await page.goto(
                    f"{DEFAULT_BASE_URL}/users/sign_up/groups/new",
                    wait_until="domcontentloaded",
                    timeout=30000,
                )
                await asyncio.sleep(2.0)
            except Exception as exc:
                _debug(f"post-welcome force-nav failed: {exc}")

        # After welcome, GitLab routes fresh accounts to /users/sign_up/groups/new
        # (group creation step). Fill it minimally and submit. _maybe_fill_groups_form
        # sekarang punya internal poll + raise on failure (sebelumnya silent).
        if "/users/sign_up/groups/new" in page.url:
            _progress("group_create", "Creating initial group…")
            await _maybe_fill_groups_form(page, account.identifier)

        # _wait_for_dashboard_or_project sekarang VERIFY ada group namespace
        # via /api/v4/namespaces (sebelumnya cuma cek URL). Kalau tidak ada
        # group setelah onboarding, raise — supaya gagal cepat dengan pesan
        # jelas alih-alih nanti error misleading di trial_claim.
        await _wait_for_dashboard_or_project(page)

        # Sanity: if we're STILL on a sign_up flow page after our handlers,
        # abort — downstream steps would fail on the wrong page.
        if "/users/sign_up/" in page.url:
            raise RetryableBatcherError(
                ErrorCode.browser_unexpected_state,
                f"Stuck on signup flow after fill attempt: {page.url}",
            )

        _progress("trial_claim", "Claiming free Ultimate trial (Singapore)…")
        await _claim_free_trial(page, account.identifier)

        _progress("duo_enable", "Enabling Duo experiment + beta features…")
        group_path = await _enable_duo_experiment(page)

        _progress("pat_generate", "Generating Personal Access Token…")
        pat = await _generate_pat(page)
        _progress("pat_done", f"PAT generated ({len(pat)} chars)")

        return {
            "pat": pat,
            "gitlab_base_url": DEFAULT_BASE_URL,
            "namespace_path": group_path,
            "username": group_path.replace("-group", "") if group_path.endswith("-group") else group_path,
            "gmail_email": account.identifier,
            "gmail_password": account.secret,
        }

    async def fetch_quota(
        self,
        account: NormalizedAccount,
        tokens: dict[str, str],
        session: Any,
    ) -> dict[str, Any] | None:
        # Quota for GitLab Duo is "trial: 30 days, ultimate tier" — there's no
        # numeric credit. The Bun runner will record models_count via the
        # post-bot createGitlabDuoAccount() call. Returning None is fine.
        return None

    async def cleanup_session(self, session: Any) -> None:
        if not isinstance(session, dict):
            return
        browser = session.get("browser")
        manager = session.get("manager")
        try:
            if browser:
                await browser.close()
        except Exception:
            pass
        try:
            if manager:
                await manager.__aexit__(None, None, None)
        except Exception:
            pass
